package org.apache.commons.csv;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class CSVFormatPrintTest {

    private Path tempFile;

    @BeforeEach
    void setUp() throws IOException {
        tempFile = Files.createTempFile("csvformat-test", ".csv");
    }

    @AfterEach
    void tearDown() throws IOException {
        if (tempFile != null) {
            Files.deleteIfExists(tempFile);
        }
    }

    @Test
    void testPrintReturnsCSVPrinterSuccessfully() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVPrinter printer = format.print(tempFile, StandardCharsets.UTF_8);
        assertNotNull(printer);
        printer.close();
    }

    @Test
    void testPrintThrowsIOExceptionWhenWriterFails() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT;

        // Spy Files to throw IOException on newBufferedWriter
        Path spyPath = Mockito.spy(tempFile);
        IOException ioException = new IOException("Mock IOException");
        // We cannot mock static Files.newBufferedWriter easily without PowerMockito or similar,
        // so we simulate by passing invalid path to cause IOException
        Path invalidPath = Path.of("/invalid/path/to/file.csv");

        assertThrows(IOException.class, () -> format.print(invalidPath, StandardCharsets.UTF_8));
    }
}
